func balanceColor(amount float64, isCredit bool) string {
	if isCredit {
		return "var(--red)"
	}
	if amount >= 0 {
		return "var(--green)"
	}
	return "var(--red)"
}

func typeBadgeClass(t string) string {
	switch t {
	case "depository":
		return "badge-depository"
	case "credit":
		return "badge-credit"
	case "investment":
		return "badge-investment"
	case "loan":
		return "badge-loan"
	}
	return ""
}

func groupAccountsByInstitution(accounts []db.ListAccountsWithInstitutionRow) map[string][]db.ListAccountsWithInstitutionRow {
	m := make(map[string][]db.ListAccountsWithInstitutionRow)
	for _, a := range accounts {
		m[a.InstitutionName] = append(m[a.InstitutionName], a)
	}
	return m
}

func institutionOrder(accounts []db.ListAccountsWithInstitutionRow) []string {
	seen := make(map[string]bool)
	var order []string
	for _, a := range accounts {
		if !seen[a.InstitutionName] {
			seen[a.InstitutionName] = true
			order = append(order, a.InstitutionName)
		}
	}
	return order
}

